  reg cond[SIZE-1];

  wire [SIZE-1:0] result_0;
  wire [SIZE-1:0] result_1 = cond[0] ? 32'h2000 : result_0;
  wire [SIZE-1:0] result_2 = cond[1] ? 32'h1000 : result_1;
  wire [SIZE-1:0] result_3 = cond[2] ? 32'h800 : result_2;
  wire [SIZE-1:0] result_4 = cond[3] ? 32'h400 : result_3;
  wire [SIZE-1:0] result_5 = cond[4] ? 32'h200 : result_4;
  wire [SIZE-1:0] result_6 = cond[5] ? 32'h100 : result_5;
  wire [SIZE-1:0] result_7 = cond[6] ? 32'h80 : result_6;
  wire [SIZE-1:0] result_8 = cond[7] ? 32'h40 : result_7;
  wire [SIZE-1:0] result_9 = cond[8] ? 32'h20 : result_8;
  wire [SIZE-1:0] result_10 = cond[9] ? 32'h10 : result_9;
  wire [SIZE-1:0] result_11 = cond[10] ? 32'h8 : result_10;
  wire [SIZE-1:0] result_12 = cond[11] ? 32'h4 : result_11;
  wire [SIZE-1:0] result_13 = cond[12] ? 32'h2 : result_12;
  wire [SIZE-1:0] result_final = cond[13] ? 32'h1 : result_13;

  wire [SIZE-1:0] result_concat;
  generate
    for (genvar i = 0; i < SIZE - 4; i+=4) begin
      assign result_concat[i+3:i] = {result_final[i+1:i], result_final[i+3:i+2]};
    end
  endgenerate
  assign result = result_concat;

  initial begin
    $write("*-* All Finished *-*\n");
    $finish;
  end
endmodule
